// // This module performs bitwise OR operations on inputs a and b, and inputs a and c, respectively, to generate outputs Z1 and Z2. It also performs a bitwise AND operation on inputs b and c to generate output Z3.
module logic_operations (
  input a,
  input b,
  input c,
  output reg Z1,
  output reg Z2,
  output reg Z3
);

  always @*
    begin
      Z1 = a & b;
      Z2 = a | c;
      Z3 = b ^ c;
    end

endmodule
